app = Flask(__name__)

@app.route("/", methods=["GET", "POST"])
def index():
    if request.method == "GET":
        return render_template("index.html")
    else:
        link = request.form["link"]
        name = request.form["name"]
        return render_template("index.html", link=link, name=name)

